const input = $input.first().json;
const url = input.url;
const method = input.method || 'GET';
const headers = input.headers || {};
const body = input.body || null;
const maxRetries = input.maxRetries || 4;
const description = input.description || 'API call';
const baseDelay = 1000;

let lastError = null;
let lastStatusCode = 0;

for (let attempt = 1; attempt <= maxRetries; attempt++) {
  try {
    const options = { method, url, headers, returnFullResponse: true };
    if (body && ['POST', 'PATCH', 'PUT'].includes(method)) {
      options.body = typeof body === 'string' ? body : JSON.stringify(body);
      if (!headers['Content-Type']) headers['Content-Type'] = 'application/json';
    }
    const response = await this.helpers.httpRequest(options);
    return [{ json: { success: true, data: response.body || response, statusCode: response.statusCode || 200, attempts: attempt, description } }];
  } catch (error) {
    lastError = error;
    lastStatusCode = error.statusCode || error.httpCode || 0;
    if (attempt < maxRetries) {
      const delay = Math.min(baseDelay * Math.pow(2, attempt - 1), 30000);
      await new Promise(r => setTimeout(r, delay));
    }
  }
}
return [{ json: { success: false, error: lastError?.message || 'Unknown error', statusCode: lastStatusCode, attempts: maxRetries, description } }];
